28	function createMultipartResponse(
29	  jobResult: Record<string, unknown>,
30	  imageContent: string = 'test-binary-content',
31	): { body: Buffer; contentType: string } {
32	  const boundary = 'test-boundary-12345';
33	  const jobJson = JSON.stringify(jobResult);
34	  const imageBuffer = Buffer.from(imageContent);
35	
36	  const parts = [
37	    `--${boundary}\r\n`,
38	    'Content-Disposition: form-data; name="job"; filename="job.json"\r\n',
39	    'Content-Type: application/json\r\n',
40	    '\r\n',
41	    jobJson,
42	    '\r\n',
43	    `--${boundary}\r\n`,
44	    'Content-Disposition: form-data; name="output"; filename="output.png"\r\n',
45	    'Content-Type: image/png\r\n',
46	    '\r\n',
47	  ];
48	
49	  const headerPart = Buffer.from(parts.join(''));
50	  const endPart = Buffer.from(`\r\n--${boundary}--\r\n`);
51	
52	  const body = Buffer.concat([headerPart, imageBuffer, endPart]);
53	
54	  return {
55	    body,
56	    contentType: `multipart/form-data; boundary=${boundary}`,
57	  };
58	}
