8	/**
9	 * Download a file from a URL and return it as a Blob.
10	 *
11	 * @param url - The URL to download from.
12	 * @param options - Optional settings for the download.
13	 * @param options.maxBytes - Maximum allowed download size in bytes. Defaults to 100 MiB.
14	 * @param options.abortSignal - An optional abort signal to cancel the download.
15	 * @returns A Promise that resolves to the downloaded Blob.
16	 *
17	 * @throws DownloadError if the download fails or exceeds maxBytes.
18	 */
19	export async function downloadBlob(
20	  url: string,
21	  options?: { maxBytes?: number; abortSignal?: AbortSignal },
22	): Promise<Blob> {
23	  validateDownloadUrl(url);
24	  try {
25	    const response = await fetch(url, {
26	      signal: options?.abortSignal,
27	    });
28	
29	    // Validate final URL after redirects to prevent SSRF via open redirect
30	    if (response.redirected) {
31	      validateDownloadUrl(response.url);
32	    }
33	
34	    if (!response.ok) {
35	      throw new DownloadError({
36	        url,
37	        statusCode: response.status,
38	        statusText: response.statusText,
39	      });
40	    }
41	
42	    const data = await readResponseWithSizeLimit({
43	      response,
44	      url,
45	      maxBytes: options?.maxBytes ?? DEFAULT_MAX_DOWNLOAD_SIZE,
46	    });
47	
48	    const contentType = response.headers.get('content-type') ?? undefined;
49	    return new Blob([data], contentType ? { type: contentType } : undefined);
50	  } catch (error) {
51	    if (DownloadError.isInstance(error)) {
52	      throw error;
53	    }
54	
55	    throw new DownloadError({ url, cause: error });
56	  }
57	}
