      providerOptions?: SharedV3ProviderMetadata;
    }
  | {
      type: 'url';
      url: string;                 // Remote image URL
      providerOptions?: SharedV3ProviderMetadata;
    };
```

### 4. Usage and Warnings

**Location:** `/packages/provider/src/image-model/v3/image-model-v3-usage.ts`

Usage information returned from the provider:

```typescript
export type ImageModelV3Usage = {
  inputTokens: number | undefined;
  outputTokens: number | undefined;
  totalTokens: number | undefined;
};
```

Warnings indicate unsupported features:

```typescript
// From provider package - uses SharedV3Warning
type SharedV3Warning = {
  type: 'unsupported';
  feature: string;
  details?: string;
} | {
  type: 'other';
  message: string;
};
```

### 5. Real Provider Implementation - OpenAI Example

**Location:** `/packages/openai/src/image/openai-image-model.ts`

This shows how to implement `ImageModelV3`:

