import {
  Experimental_VideoModelV3,
  ImageModelV3,
  NoSuchModelError,
  ProviderV3,
  SpeechModelV3,
  TranscriptionModelV3,
} from '@ai-sdk/provider';
import type { FetchFunction } from '@ai-sdk/provider-utils';
import {
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { FalImageModel } from './fal-image-model';
import { FalImageModelId } from './fal-image-settings';
import { FalTranscriptionModelId } from './fal-transcription-options';
import { FalTranscriptionModel } from './fal-transcription-model';
import { FalSpeechModelId } from './fal-speech-settings';
import { FalSpeechModel } from './fal-speech-model';
import { FalVideoModel } from './fal-video-model';
import { FalVideoModelId } from './fal-video-settings';
import { VERSION } from './version';

// Settings interface for configuration
export interface FalProviderSettings {
  /**
   * fal.ai API key. Default value is taken from the `FAL_API_KEY` environment
   * variable, falling back to `FAL_KEY`.
   */
  apiKey?: string;

  /**
   * Base URL for the API calls.
   * The default prefix is `https://fal.run`.
   */
  baseURL?: string;

  /**
   * Custom headers to include in the requests.
   */
  headers?: Record<string, string>;

  /**
   * Custom fetch implementation. You can use it as a middleware to intercept
   * requests, or to provide a custom fetch implementation for e.g. testing.
   */
  fetch?: FetchFunction;
}

// Provider interface defining what methods are available
export interface FalProvider extends ProviderV3 {
  /**
   * Creates a model for image generation.
   */
  image(modelId: FalImageModelId): ImageModelV3;

  /**
   * Creates a model for image generation.
   */
  imageModel(modelId: FalImageModelId): ImageModelV3;

  /**
   * Creates a model for transcription.
   */
  transcription(modelId: FalTranscriptionModelId): TranscriptionModelV3;

  /**
   * Creates a model for video generation.
   */
  video(modelId: FalVideoModelId): Experimental_VideoModelV3;

  /**
   * Creates a model for video generation.
   */
  videoModel(modelId: FalVideoModelId): Experimental_VideoModelV3;

  /**
   * Creates a model for speech generation.
   */
  speech(modelId: FalSpeechModelId): SpeechModelV3;

  /**
   * @deprecated Use `embeddingModel` instead.
   */
  textEmbeddingModel(modelId: string): never;
}

const defaultBaseURL = 'https://fal.run';

// API Key loading with fallback to env variables
function loadFalApiKey({
  apiKey,
  description = 'fal.ai',
}: {
  apiKey: string | undefined;
  description?: string;
}): string {
  if (typeof apiKey === 'string') {
    return apiKey;
  }

  if (apiKey != null) {
    throw new Error(`${description} API key must be a string.`);
  }

  if (typeof process === 'undefined') {
    throw new Error(
      `${description} API key is missing. Pass it using the 'apiKey' parameter. Environment variables are not supported in this environment.`,
    );
  }

  let envApiKey = process.env.FAL_API_KEY;
  if (envApiKey == null) {
    envApiKey = process.env.FAL_KEY;
  }

  if (envApiKey == null) {
    throw new Error(
      `${description} API key is missing. Pass it using the 'apiKey' parameter or set either the FAL_API_KEY or FAL_KEY environment variable.`,
    );
  }

  if (typeof envApiKey !== 'string') {
    throw new Error(
      `${description} API key must be a string. The value of the environment variable is not a string.`,
    );
  }

  return envApiKey;
}

/**
 * Create a fal.ai provider instance.
 */
export function createFal(options: FalProviderSettings = {}): FalProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);

  // Closure that creates headers with auth and user agent
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Key ${loadFalApiKey({
          apiKey: options.apiKey,
        })}`,
        ...options.headers,
      },
      `ai-sdk/fal/${VERSION}`,
    );

  // Factory functions for each model type
  const createImageModel = (modelId: FalImageModelId) =>
    new FalImageModel(modelId, {
      provider: 'fal.image',
      baseURL: baseURL ?? defaultBaseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const createSpeechModel = (modelId: FalSpeechModelId) =>
    new FalSpeechModel(modelId, {
      provider: `fal.speech`,
      url: ({ path }) => path,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const createTranscriptionModel = (modelId: FalTranscriptionModelId) =>
    new FalTranscriptionModel(modelId, {
      provider: `fal.transcription`,
      url: ({ path }) => path,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const createVideoModel = (modelId: FalVideoModelId) =>
    new FalVideoModel(modelId, {
      provider: 'fal.video',
      url: ({ path }) => path,
      headers: getHeaders,
      fetch: options.fetch,
    });

  // Error handler for unsupported model types
  const embeddingModel = (modelId: string) => {
    throw new NoSuchModelError({
      modelId,
      modelType: 'embeddingModel',
    });
  };

  // Return the provider object implementing ProviderV3 interface
  return {
    specificationVersion: 'v3' as const,
    imageModel: createImageModel,
    image: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({
        modelId,
        modelType: 'languageModel',
      });
    },
    speech: createSpeechModel,
    embeddingModel,
    textEmbeddingModel: embeddingModel,
    transcription: createTranscriptionModel,
    video: createVideoModel,
    videoModel: createVideoModel,
  };
}

/**
 * Default fal.ai provider instance.
 */
export const fal = createFal();
```

**Key Architecture Points:**

1. **Settings Interface** (`FalProviderSettings`):
   - API key (from parameter or env var)
   - Base URL (default to `https://fal.run`)
   - Custom headers
   - Custom fetch function

2. **Provider Interface** (`FalProvider extends ProviderV3`):
   - Defines all available methods
   - Each method creates a typed model instance
   - Throws `NoSuchModelError` for unsupported model types

3. **Factory Function** (`createFal`):
   - Takes optional settings
   - Returns provider object
   - Creates model factories that are closures over the settings
   - Handles API key loading with environment variable fallback
   - Adds user-agent suffix for tracking

4. **Default Instance** (`export const fal = createFal()`):
   - Pre-instantiated with default settings
   - Users can also call `createFal(options)` for custom settings

