import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { FetchFunction, InferSchema, Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { pixelArtFailedResponseHandler } from './pixelart-error';
import type { PixelArtImageModelId } from './pixelart-image-settings';

export interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

const pixelArtImageResponseSchema = z.object({
  created: z.number(),
  data: z.array(
    z.object({
      b64_json: z.string(),
      seed: z.number().nullish(),
    }),
  ),
});

export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * The visual style of the generated pixel art image.
       * - "pixel": Classic pixel art style
       * - "retro": Retro 8/16-bit inspired style
       * - "8bit": Pure 8-bit aesthetic
       */
      style: z.enum(['pixel', 'retro', '8bit']).optional(),
      /**
       * The pixel density (pixels per unit) of the output image.
       * Higher values produce finer detail. Range: 1–64.
       */
      pixelDensity: z.number().int().min(1).max(64).optional(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const { prompt, n, size, aspectRatio, seed, files, mask, providerOptions, headers: requestHeaders, abortSignal } = options;

    const warnings: Array<SharedV3Warning> = [];

    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    // Parse size ("WIDTHxHEIGHT") into width and height
    let width: number | undefined;
    let height: number | undefined;
    if (size) {
      const [widthStr, heightStr] = size.split('x');
      width = Number(widthStr);
      height = Number(heightStr);
      if (
        !widthStr ||
        !heightStr ||
        !Number.isFinite(width) ||
        !Number.isFinite(height)
      ) {
        warnings.push({
          type: 'unsupported',
          feature: 'size',
          details: `Invalid size format: ${size}. Expected format: WIDTHxHEIGHT (e.g., 512x512)`,
        });
        width = undefined;
        height = undefined;
      }
    }

    // Warn on unsupported parameters
    if (n != null && n > 1) {
      warnings.push({
        type: 'unsupported',
        feature: 'n',
        details: 'PixelArt only supports generating one image at a time (n=1).',
      });
    }

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspectRatio. Use the size parameter (WIDTHxHEIGHT) instead.',
      });
    }

    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'image editing (files)',
        details: 'PixelArt does not support image editing with input files.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask (inpainting)',
        details: 'PixelArt does not support inpainting with a mask.',
      });
    }

    // Build request body
    const body: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n: 1,
      response_format: 'b64_json',
    };

    if (width !== undefined) {
      body.width = width;
    }
    if (height !== undefined) {
      body.height = height;
    }
    if (seed !== undefined) {
      body.seed = seed;
    }
    if (pixelArtOptions?.style !== undefined) {
      body.style = pixelArtOptions.style;
    }
    if (pixelArtOptions?.pixelDensity !== undefined) {
      body.pixel_density = pixelArtOptions.pixelDensity;
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(
        await resolve(this.config.headers),
        requestHeaders,
      ),
      body,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: value.data.map(item => item.b64_json),
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          created: value.created,
          seeds: value.data.map(item => item.seed ?? null),
        },
      },
    };
  }
}

