import type { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixelart-image-model';

const prompt = 'A retro space invader';
const apiURL = 'https://api.pixelart.ai/v1/images/generate';

const defaultResponse = {
  created: 1700000000,
  data: [{ b64_json: 'dGVzdA==', seed: 42 }],
};

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixelart-v1', {
    provider: 'pixelart.image',
    baseURL: 'https://api.pixelart.ai/v1',
    headers: headers ?? (() => ({ Authorization: 'Bearer test-key' })),
    fetch,
    _internal: { currentDate },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    [apiURL]: {
      response: {
        type: 'json-value',
        body: defaultResponse,
      },
    },
  });

  describe('doGenerate', () => {
    it('passes model, prompt, and response_format in request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 1,
        response_format: 'b64_json',
      });
    });

    it('passes width and height when size is provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 1,
        response_format: 'b64_json',
        width: 512,
        height: 512,
      });
    });

    it('passes seed in request body when provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: 99,
        providerOptions: {},
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 1,
        response_format: 'b64_json',
        seed: 99,
      });
    });

    it('passes style from providerOptions in request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { style: 'retro' },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 1,
        response_format: 'b64_json',
        style: 'retro',
      });
    });

    it('passes pixel_density from pixelDensity providerOption in request body', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { pixelDensity: 16 },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 1,
        response_format: 'b64_json',
        pixel_density: 16,
      });
    });

    it('passes both style and pixelDensity from providerOptions', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {
          pixelart: { style: '8bit', pixelDensity: 8 },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        model: 'pixelart-v1',
        prompt,
        n: 1,
        response_format: 'b64_json',
        style: '8bit',
        pixel_density: 8,
      });
    });

    it('returns base64 image string', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.images).toHaveLength(1);
      expect(result.images[0]).toBe('dGVzdA==');
    });

    it('warns when n > 1', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 3,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toContainEqual({
        type: 'unsupported',
        feature: 'n',
        details: 'PixelArt only supports generating one image at a time (n=1).',
      });
    });

    it('warns when aspectRatio is provided', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: '16:9',
        seed: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toContainEqual({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspectRatio. Use the size parameter (WIDTHxHEIGHT) instead.',
      });
    });

    it('warns when files are provided', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: [{ type: 'url', url: 'https://example.com/image.png' }],
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toContainEqual({
        type: 'unsupported',
        feature: 'image editing (files)',
        details: 'PixelArt does not support image editing with input files.',
      });
    });

    it('warns when mask is provided', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: { type: 'url', url: 'https://example.com/mask.png' },
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toContainEqual({
        type: 'unsupported',
        feature: 'mask (inpainting)',
        details: 'PixelArt does not support inpainting with a mask.',
      });
    });

    it('warns on invalid size format', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: 'invalid' as `${number}x${number}`,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.warnings).toContainEqual({
        type: 'unsupported',
        feature: 'size',
        details:
          'Invalid size format: invalid. Expected format: WIDTHxHEIGHT (e.g., 512x512)',
      });
    });

    it('merges provider-level and request-level headers', async () => {
      const model = createBasicModel({
        headers: () => ({
          Authorization: 'Bearer test-key',
          'X-Provider-Header': 'provider-value',
        }),
      });

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
        headers: {
          'X-Request-Header': 'request-value',
        },
      });

      expect(server.calls[0].requestHeaders).toMatchObject({
        authorization: 'Bearer test-key',
        'x-provider-header': 'provider-value',
        'x-request-header': 'request-value',
      });
    });

    it('includes Authorization header with Bearer prefix', async () => {
      const model = createBasicModel({
        headers: () => ({ Authorization: 'Bearer my-api-key' }),
      });

      await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(server.calls[0].requestHeaders.authorization).toBe(
        'Bearer my-api-key',
      );
    });

    it('returns response with modelId, timestamp, and headers', async () => {
      const testDate = new Date('2024-01-01T00:00:00Z');
      const model = createBasicModel({
        currentDate: () => testDate,
      });

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.response).toStrictEqual({
        modelId: 'pixelart-v1',
        timestamp: testDate,
        headers: expect.any(Object),
      });
    });

    it('returns providerMetadata with created and seeds', async () => {
      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.providerMetadata?.pixelart).toStrictEqual({
        created: 1700000000,
        seeds: [42],
      });
    });

    it('returns null in seeds when seed is absent from response', async () => {
      server.urls[apiURL].response = {
        type: 'json-value',
        body: {
          created: 1700000001,
          data: [{ b64_json: 'aW1hZ2U=' }],
        },
      };

      const model = createBasicModel();

      const result = await model.doGenerate({
        prompt,
        files: undefined,
        mask: undefined,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        providerOptions: {},
      });

      expect(result.providerMetadata?.pixelart).toStrictEqual({
        created: 1700000001,
        seeds: [null],
      });
    });

    it('throws on API error response', async () => {
      server.urls[apiURL].response = {
        type: 'error',
        status: 400,
        body: JSON.stringify({ error: { message: 'Invalid prompt provided' } }),
      };

      const model = createBasicModel();

      await expect(
        model.doGenerate({
          prompt,
          files: undefined,
          mask: undefined,
          n: 1,
          size: undefined,
          aspectRatio: undefined,
          seed: undefined,
          providerOptions: {},
        }),
      ).rejects.toMatchObject({
        message: 'Invalid prompt provided',
        statusCode: 400,
        url: apiURL,
      });
    });
  });

  describe('constructor', () => {
    it('exposes correct provider and model information', () => {
      const model = createBasicModel();

      expect(model.provider).toBe('pixelart.image');
      expect(model.modelId).toBe('pixelart-v1');
      expect(model.specificationVersion).toBe('v3');
      expect(model.maxImagesPerCall).toBe(1);
    });
  });
});

